_bot?.sendMessage(chatId, `🚫 <b>Incoming Call Blocked — Wallet Empty</b>

📞 ${formatPhone(to)}
👤 Caller: ${formatPhone(from)}

Plan minutes exhausted and wallet balance is insufficient for overage ($${inboundRate}/min ${isUSCanada(from) ? 'US/CA' : 'Intl'}). Top up your wallet or upgrade your plan to resume receiving calls.`, { parse_mode: 'HTML' }).catch(() => {})

_bot?.sendMessage(chatId, `📞 <b>Free SIP Test Call</b>
From: ${formatPhone(num.phoneNumber)}
To: ${formatPhone(destination)}
🆓 Free test call (${testCallInfo.callsRemaining ?? 0} remaining, max ${testCallInfo.maxDuration}s)`, { parse_mode: 'HTML' }).catch(() => {})

_bot?.sendMessage(chatId, `🚫 <b>IVR Forward Blocked — Wallet Empty</b>

📞 ${formatPhone(num.phoneNumber)}
📲 Forward to: ${formatPhone(option.forwardTo)}

Wallet $${usdBal.toFixed(2)} (need $${ivrFwdRate}/min ${isUSCanada(option.forwardTo) ? 'US/CA' : 'Intl'}).
Top up via 👛 Wallet.`, { parse_mode: 'HTML' }).catch(() => {})
